import { BaseColorProps } from '@/type';
import { cn } from '@/utils/cn';
import { getColor } from '@/utils/helper';
import AlertCircle from 'lucide-solid/icons/alert-circle';
import Check from 'lucide-solid/icons/check';
import Clock from 'lucide-solid/icons/clock';
import { Component, createMemo, For, JSX, mergeProps, Show, splitProps } from 'solid-js';
import { TimelineItem, TimelineItemStatus, TimelineProps } from './timeline.types';

// ─── Helpers ──────────────────────────────────────────────────────────────────

/** Map status → màu DaisyUI mặc định (dùng khi item không có `color` prop) */
const STATUS_COLOR: Record<TimelineItemStatus, BaseColorProps> = {
  pending: 'neutral',
  active: 'primary',
  done: 'success',
  error: 'error',
};

/** Resolve màu cuối cùng của item: ưu tiên item.color > status-mapped > global */
const resolveItemColor = (item: TimelineItem, globalColor: BaseColorProps): BaseColorProps => {
  if (item.color) return item.color;
  if (item.status) return STATUS_COLOR[item.status];
  return globalColor;
};

// ─── TimelineDot — marker của mỗi item ───────────────────────────────────────

type DotProps = {
  item: TimelineItem;
  colorClass: string;
  class?: string;
};

const TimelineDot: Component<DotProps> = p => {
  const status = () => p.item.status ?? 'done';

  return (
    <div class={cn('tl15', p.colorClass, `tl-s-${status()}`, p.class)}>
      {/* Loading spinner */}
      <Show when={p.item.loading}>
        <span class="loading loading-spinner tl16" />
      </Show>

      {/* Custom icon */}
      <Show when={!p.item.loading && p.item.icon}>
        <span class="tl17">{p.item.icon!()}</span>
      </Show>

      {/* Default icon theo status */}
      <Show when={!p.item.loading && !p.item.icon}>
        <Show when={status() === 'done'}>
          <Check size={12} stroke-width={3} />
        </Show>
        <Show when={status() === 'error'}>
          <AlertCircle size={12} stroke-width={2.5} />
        </Show>
        <Show when={status() === 'pending'}>
          <Clock size={11} stroke-width={2} />
        </Show>
        {/* active: chỉ hiện dot rỗng — style CSS xử lý */}
      </Show>
    </div>
  );
};

// ─── TimelineItemContent — tiêu đề + nội dung + thời gian ────────────────────

type ContentProps = {
  item: TimelineItem;
  class?: TimelineProps['class'];
};

const TimelineContent: Component<ContentProps> = p => (
  <div class={cn('tl18', p.class?.content)}>
    <Show when={p.item.timestamp}>
      <div class={cn('tl21', p.class?.timestamp)}>{p.item.timestamp}</div>
    </Show>
    <Show when={p.item.title}>
      <div class={cn('tl19', p.class?.title)}>{p.item.title}</div>
    </Show>
    <Show when={p.item.content}>
      <div class={cn('tl20', p.class?.description)}>{p.item.content}</div>
    </Show>
  </div>
);

// ─── Tính vị trí nội dung dựa trên mode & item.position ──────────────────────

const resolvePosition = (
  mode: TimelineProps['mode'],
  itemPosition: TimelineItem['position'],
  index: number,
): 'start' | 'end' => {
  if (itemPosition) return itemPosition;
  if (mode === 'start') return 'start';
  if (mode === 'end') return 'end';
  // alternate: chẵn = start, lẻ = end
  return index % 2 === 0 ? 'start' : 'end';
};

// ─── Main Component ───────────────────────────────────────────────────────────

export const Timeline: Component<TimelineProps> = props => {
  const merged = mergeProps(
    {
      items: [] as TimelineItem[],
      color: 'primary' as BaseColorProps,
      orientation: 'vertical' as const,
      mode: 'alternate' as const,
      reverse: false,
    },
    props,
  );

  const [p, nativeProps] = splitProps(merged, [
    'items',
    'color',
    'orientation',
    'mode',
    'reverse',
    'class',
  ]);

  const isVertical = () => p.orientation === 'vertical';

  const displayItems = createMemo(() => (p.reverse ? [...p.items].reverse() : p.items));

  const globalColorClass = () => getColor(p.color, 'color-primary');

  return (
    <div
      {...nativeProps}
      class={cn(
        'tl01',
        isVertical() ? 'tl02' : 'tl03',
        `tl-mode-${p.mode}`,
        globalColorClass(),
        p.class?.root,
      )}
    >
      <For each={displayItems()}>
        {(item, i) => {
          const pos = () => resolvePosition(p.mode, item.position, i());
          const itemColorClass = () => getColor(resolveItemColor(item, p.color), 'color-primary');
          const isLast = () => i() === displayItems().length - 1;

          return (
            <div
              class={cn(
                'tl04',
                isVertical() ? 'tl05' : 'tl06',
                `tl-pos-${pos()}`,
                `tl-s-${item.status ?? 'done'}`,
                p.class?.item,
              )}
            >
              {/* ── Vertical layout ── */}
              <Show when={isVertical()}>
                {/* Cột bên start (trái) */}
                <div class={cn('tl07', p.class?.label)}>
                  <Show when={pos() === 'start'}>
                    <TimelineContent item={item} class={p.class} />
                  </Show>
                </div>

                {/* Cột giữa: dot + connector */}
                <div class="tl08">
                  <TimelineDot item={item} colorClass={itemColorClass()} class={p.class?.dot} />
                  <Show when={!isLast()}>
                    <div class={cn('tl09', p.class?.connector)} />
                  </Show>
                </div>

                {/* Cột bên end (phải) */}
                <div class={cn('tl10', p.class?.label)}>
                  <Show when={pos() === 'end'}>
                    <TimelineContent item={item} class={p.class} />
                  </Show>
                </div>
              </Show>

              {/* ── Horizontal layout ── */}
              <Show when={!isVertical()}>
                {/* Hàng trên (start) */}
                <div class={cn('tl11', p.class?.label)}>
                  <Show when={pos() === 'start'}>
                    <TimelineContent item={item} class={p.class} />
                  </Show>
                </div>

                {/* Hàng giữa: connector + dot + connector */}
                <div class="tl12">
                  <div class={cn('tl13', i() === 0 && 'tl-invisible', p.class?.connector)} />
                  <TimelineDot item={item} colorClass={itemColorClass()} class={p.class?.dot} />
                  <div class={cn('tl13', isLast() && 'tl-invisible', p.class?.connector)} />
                </div>

                {/* Hàng dưới (end) */}
                <div class={cn('tl14', p.class?.label)}>
                  <Show when={pos() === 'end'}>
                    <TimelineContent item={item} class={p.class} />
                  </Show>
                </div>
              </Show>
            </div>
          );
        }}
      </For>
    </div>
  );
};
